export const EXAM_PACK_2026: ExamCategory[] = [
  {
    id: "scenario2026",
    title: "Scenario Questions 2026",
    icon: React.createElement(Target, { className: "w-5 h-5" }),
    color: "text-amber-600",
    bg: "bg-amber-50",
    questions: [
      { id: "sc01", q: "Your S/4HANA production system is reported down by business users at 8:05 AM. Walk through your incident response.", a: "Start by classifying the outage by layer: network, OS, database, SAP instance, or front-end. Validate scope using user symptoms, monitoring alerts, and a quick check of load balancer or URL reachability. Check OS health, HANA status, sapstartsrv, dispatcher, and message server logs in that order. Communicate an initial status update to stakeholders within 5 minutes. Stabilize service, document the timeline, and perform root cause analysis after recovery — never close an incident without RCA.", level: "senior", tags: ["incident", "P1", "HANA", "production"] },
      { id: "sc02", q: "After a brownfield S/4HANA conversion, critical transactions are slower than in ECC. What is your diagnostic approach?", a: "Compare pre- and post-conversion performance baselines. Review ST03N, ST12, SQL trace, expensive statements in HANA Cockpit, HANA memory usage, and delta merge behavior. Verify whether legacy custom code was carried over without HANA optimization (missing push-down, SELECT *, nested loops). Separate infrastructure issues from application design issues. End with a remediation plan covering code push-down, SQL optimization, statistics refresh, archiving, and parameter review.", level: "senior", tags: ["performance", "S/4HANA", "HANA", "ST12"] },
      { id: "sc03", q: "A client asks whether to choose RISE with SAP or a customer-managed deployment on AWS. How do you frame your answer?", a: "Frame the decision around control, responsibility, speed, flexibility, compliance, and operating model. RISE is suitable when the client wants SAP-managed cloud ERP transformation with reduced infrastructure ownership and faster time-to-value. Customer-managed on AWS is stronger when the client needs more control over architecture, tooling, integrations, scheduling, and operations. Compare cost transparency, SLA ownership, change windows, and security responsibilities explicitly.", level: "senior", tags: ["RISE", "AWS", "cloud", "architecture"] },
      { id: "sc04", q: "HANA database memory keeps growing. The ops team wants to restart the database weekly. What do you say?", a: "A weekly restart is not a fix — it is a symptom of poor governance. First analyze resident memory, allocated memory, peak usage, unload behavior, table growth, delta merge, expensive statements, and long-running jobs. Identify whether the cause is workload design, poor housekeeping, oversized data retention, or application behavior. The response is to tune and govern the workload, not normalize restarts as an operational habit.", level: "senior", tags: ["HANA", "memory", "performance", "governance"] },
      { id: "sc05", q: "A transport import to production finishes with return code 8 and the business process breaks. What is your response?", a: "Immediately identify the transport, impacted object list, logs, import queue sequence, and whether dependent transports were missed. Coordinate with development and functional teams to assess business impact. Decide between rollback (import reverse transport), correction transport, or emergency repair based on risk. Review transport governance to prevent recurrence: sequencing, approvals, retrofit controls, and cutover validation.", level: "senior", tags: ["transport", "RC8", "production", "rollback"] },
      { id: "sc06", q: "A company plans to move SAP workloads to Azure. The business fears downtime and performance issues. Structure your migration strategy.", a: "Start with workload discovery, dependency mapping, sizing validation, network design, HA/DR requirements, and cutover strategy. Classify systems by migration pattern: lift-and-shift, replatform, or redesign. Run sandbox and non-production pilots first. Define rollback paths, measure latency to dependent systems, and align migration with business freeze windows. Cloud migration is a business program, not a weekend activity.", level: "senior", tags: ["Azure", "migration", "cloud", "strategy"] },
      { id: "sc07", q: "Design a disaster recovery strategy for a mission-critical SAP landscape.", a: "Define business RTO and RPO first — DR starts with business expectations, not technology. Then design database replication, application layer recovery, backup strategy, DNS or routing failover, storage recovery, testing cadence, runbooks, and operational ownership. Ensure regular failover drills, automation where possible, and clear decision criteria for invoking DR. A DR document that has never been tested is not DR readiness.", level: "senior", tags: ["DR", "HA", "RTO", "RPO"] },
      { id: "sc08", q: "A customer wants single sign-on across SAP GUI, Fiori, and BTP applications. How do you approach it?", a: "Define the identity architecture first: corporate IdP, IAS, IPS, trust relationships, federation, provisioning model, and authorization boundaries. Map authentication methods by channel — SAML or OIDC for web apps, SNC or certificate for SAP GUI. Address user lifecycle, emergency access, MFA, and fallback procedures. SSO without identity governance is a security risk, not a convenience feature.", level: "senior", tags: ["SSO", "IAS", "BTP", "Fiori"] },
      { id: "sc09", q: "An SAP Cloud Connector integration to BTP suddenly stops working. What do you check first?", a: "Check tunnel health, certificate validity, destination configuration, subaccount mapping, backend reachability, and recent transport or firewall changes. Verify whether the problem is connector-side, destination-side, identity-related, or backend application-related. Correlate logs from Cloud Connector (ljs_trace.log), BTP Cockpit, and SM21/STRUST on the on-premise side. Validate whether the outage affects one service or all connected services.", level: "mid", tags: ["SCC", "BTP", "connectivity", "troubleshooting"] },
      { id: "sc10", q: "Your client wants to adopt Clean Core, but their ECC system is heavily customized. What is your recommendation?", a: "Do not promise instant clean core. First classify custom objects into keep, retire, redesign, or move to side-by-side extensibility. Align future enhancements to approved extension patterns — BTP side-by-side, BAdI, CDS Views. The recommendation is a governed transition plan that reduces modification debt over releases, not a slogan. Show the client a roadmap with measurable milestones.", level: "senior", tags: ["clean core", "S/4HANA", "customization", "migration"] },
      { id: "sc11", q: "HANA system replication status shows inconsistent behavior during monitoring. What would you do?", a: "Verify primary-secondary roles, replication mode (sync/async), operation mode, log shipping health, network stability, and alert history. Compare system replication state from HANA tools (hdbnsutil -sr_state, hdbcons) and OS-level observations. Investigate replication lag, storage performance, and failover readiness. Never claim DR readiness until replication is demonstrably stable under a representative workload.", level: "senior", tags: ["HANA", "HSR", "replication", "DR"] },
      { id: "sc12", q: "A major background job chain is missing its SLA every month-end. How do you investigate?", a: "Analyze job definitions, dependencies, start conditions, workload peaks, spool volume, locking patterns, DB contention, and external scheduler interactions. Review whether the issue is due to resource bottlenecks, poor sequencing, or data volume growth. Optimize schedule design, parallelism, housekeeping, and escalation thresholds. Month-end issues are usually systemic governance failures, not isolated job problems.", level: "senior", tags: ["background jobs", "SM37", "month-end", "SLA"] },
      { id: "sc13", q: "Fiori launchpad is working but classic SAP GUI transactions behind an RFC fail intermittently. What is your approach?", a: "Separate front-end availability from backend integration health. Check SM59 destinations, gateway logs, ICM health, network path, certificate validity, user mapping, and workload spikes at failure times. Intermittent RFC failures usually point to integration-layer instability, gateway timeouts, or dependent system issues. Use SM58 (tRFC log) and SM21 for correlation. Show layered troubleshooting rather than assuming SAP itself is entirely down.", level: "mid", tags: ["RFC", "Fiori", "SM59", "troubleshooting"] },
      { id: "sc14", q: "A client wants near-zero downtime for a production upgrade. What options do you discuss?", a: "Discuss business tolerance, technical constraints, custom code complexity, add-ons, and supported downtime minimization approaches. Near-zero downtime requires planning at database, application, integration, and business process levels simultaneously. The right answer balances tooling (SUM DMO near-zero option), cutover design, data consistency checks, fallback path, and realistic downtime expectations rather than making promises based on one tool feature alone.", level: "senior", tags: ["upgrade", "downtime", "SUM", "S/4HANA"] },
      { id: "sc15", q: "During a carve-out project, the customer asks whether one SAP system can simply be copied and split later. How do you respond?", a: "Explain that carve-out is primarily a business-data and process-separation problem, not just a technical copy exercise. Assess company codes, plants, users, interfaces, authorizations, legal data retention, and historical data needs. Design the separation approach with governance, data validation, transport control, and post-cutover reconciliation. Technically, tools like SAP LT or third-party carve-out tools handle extraction, but the business design must precede technical execution.", level: "senior", tags: ["carve-out", "system copy", "SWPM", "data"] },
      { id: "sc16", q: "The SAP security team finds generic users with broad access in production. How do you handle it?", a: "Classify the exposure level immediately: review who uses the accounts, what interfaces depend on them, and whether there is audit impact. Define a remediation path: named users where possible, technical system users with least privilege where required, password control, logging, and ownership assignment. Balance security enforcement with operational continuity — emergency access procedures must be defined before privileged accounts are removed.", level: "senior", tags: ["security", "generic users", "SU01", "IAM"] },
      { id: "sc17", q: "Management asks why you want observability tools when they already have CCMS-style monitoring. What do you say?", a: "Modern observability goes beyond threshold alerts. It correlates logs, metrics, events, traces, and dependency behavior across SAP and non-SAP components — essential in hybrid and cloud-based landscapes. CCMS tells you something is wrong; observability helps explain why and where the problem started. In a landscape with BTP, Integration Suite, and cloud databases, CCMS alone covers only the ABAP layer.", level: "senior", tags: ["observability", "CCMS", "monitoring", "Cloud ALM"] },
      { id: "sc18", q: "A batch interface from a non-SAP platform starts duplicating records into SAP. What is your response?", a: "First contain the issue by stopping or isolating the interface if the business allows. Identify whether duplication is caused by source retries, middleware reprocessing, missing idempotency checks, or SAP-side acknowledgment failure. Then address technical correction, data cleanup (with functional team), and interface design hardening. Implement idempotency keys or IDoc deduplication at the IDoc/middleware layer to prevent recurrence.", level: "senior", tags: ["interface", "IDOC", "duplicate", "integration"] },
      { id: "sc19", q: "Your company wants to automate Basis operations. Where would you start?", a: "Start with repeatable, high-volume, low-risk tasks: system health checks, user lifecycle operations, certificate expiry alerts, backup validation, transport reporting, and housekeeping (spool, ABAP dump cleanup). Define control points, approvals, rollback procedures, auditability, and monitoring for the automation itself. Good automation in SAP is controlled and observable — not just scripted. Automate governance, not chaos.", level: "senior", tags: ["automation", "DevOps", "operations", "scripting"] },
      { id: "sc20", q: "A network team insists SAP slowness is an application issue; SAP team suspects network latency. How do you resolve the dispute?", a: "Establish evidence with timestamped measurements from both sides. Compare application response time (ST05/ST12), DB time, RFC duration (SM59 trace), packet path behavior, and cross-site latency during peak periods. Use network captures (tcpdump/Wireshark) correlated with SAP trace timestamps. Present data calmly to both teams — evidence-based triage beats blame. Bring in the network and SAP teams to review data together.", level: "senior", tags: ["performance", "network", "latency", "ST05"] },
      { id: "sc21", q: "How do you justify SAP Cloud ALM to a client still using Solution Manager today?", a: "Explain the shift in SAP operations toward cloud-centric lifecycle management, especially for hybrid and cloud landscapes. Cloud ALM supports implementation and operations monitoring natively for BTP, S/4HANA Cloud, and hybrid systems. Still, assess the customer's current landscape, operational processes, and SolMan investments before defining a migration or coexistence strategy. Avoid tool evangelism — focus on fit-for-purpose governance and measurable improvement.", level: "senior", tags: ["Cloud ALM", "SolMan", "strategy", "governance"] },
      { id: "sc22", q: "A production system restart resolves the issue but the business asks you to close the incident. What would you do?", a: "Restore service first, but never treat the restart as root cause. Document the timeline, collect logs before rotation where possible, review ABAP dumps (ST22) and traces, and open a follow-up root cause work item. Senior operations means fixing the reason, not only resetting the symptom. Closing without RCA exposes the business to recurrence.", level: "senior", tags: ["incident", "RCA", "governance", "operations"] },
      { id: "sc23", q: "A customer wants to extend S/4HANA with custom apps. How do you decide between embedded development and BTP side-by-side extension?", a: "Use criteria: clean core policy, lifecycle independence, integration complexity, performance needs, security boundaries, and ownership model. Embedded ABAP is justified when the requirement is tightly coupled to core transactional logic and cannot tolerate latency. BTP side-by-side is better when the requirement should remain decoupled, release-independent, and cloud-ready. Document the decision rationale.", level: "senior", tags: ["BTP", "clean core", "extensibility", "S/4HANA"] },
      { id: "sc24", q: "A HANA backup finished successfully but the storage team later reports snapshot inconsistency. What is your next step?", a: "Validate backup catalog consistency using HANA Backup Catalog (DBACOCKPIT → Backup → Catalog), test recovery usability in a sandbox, and check storage-layer dependencies. Never rely on green backup status alone. A strong answer emphasizes restore testing — backup success without recoverability is not operational readiness. Open a P2 ticket for the storage inconsistency and update backup SLA documentation.", level: "senior", tags: ["HANA", "backup", "DR", "recovery"] },
      { id: "sc25", q: "Business wants to decommission several satellite SAP systems after consolidation. What concerns do you raise?", a: "Raise interface dependencies, historical data access needs, legal retention requirements, audit access, user communication, archive strategy (SARA/ArchiveLink), and fallback needs. Decommissioning is not deleting servers — it is retiring a business capability safely. Define a structured decommission plan with evidence trails, data archival confirmation, interface shutdown sequences, and stakeholder sign-offs.", level: "senior", tags: ["decommission", "archiving", "SARA", "governance"] },
      { id: "sc26", q: "During an SAP on GCP design workshop, the client asks how to place app servers across zones. What is your answer?", a: "Design for availability, latency, and operational simplicity. Place ASCS (Central Services) with HA across zones (Pacemaker + zone-aware storage or GCP MIG). Application servers can be distributed across zones for failure isolation. Database (HANA) HSR should be zone-aware. Consider inter-zone traffic costs and latency impact on tightly coupled RFC flows. Multi-zone design is about service continuity, not using every zone available.", level: "senior", tags: ["GCP", "HA", "zones", "architecture"] },
      { id: "sc27", q: "An interviewer says 'Basis is becoming obsolete because cloud vendors manage everything now.' How do you respond?", a: "Basis is evolving, not disappearing. The focus is shifting from pure server administration to architecture, integration, governance, resilience, security, and service orchestration across SAP and non-SAP platforms. In managed cloud models, technical ownership changes, but accountability for business continuity, integration design, security governance, and platform quality remains critical. The scope expands — it does not contract.", level: "senior", tags: ["career", "cloud", "strategy", "2026"] },
      { id: "sc28", q: "A client wants one global SAP transport path but regional teams need release flexibility. How do you design the governance?", a: "Introduce a controlled transport governance model with release calendars, emergency paths, segregation of duties, and full dependency visibility. Define global baseline releases (e.g., quarterly) and approved emergency transport lanes with escalation controls. Regional teams get release flexibility within guardrails — not unchecked transport authority. Include audit trails, approval ownership, and rollback paths.", level: "senior", tags: ["transport", "governance", "STMS", "release"] },
      { id: "sc29", q: "How would you handle a failed Unicode conversion rehearsal?", a: "Treat the rehearsal as a success if it revealed issues early. Analyze technical failure points, data problems (MDMP characters, encoding errors), custom code impact (UCCHECK results), and elapsed timings. Update the runbook, sizing, and fallback steps before the next rehearsal. Rehearsals exist to find issues — the mature response is learning and improving each iteration, not blame.", level: "senior", tags: ["Unicode", "conversion", "SUM", "rehearsal"] },
      { id: "sc30", q: "Your SAP Web Dispatcher becomes a bottleneck after a Fiori rollout. What do you investigate?", a: "Review sizing (connections, threads, concurrent users), SSL offloading performance, routing rules, timeout settings, certificate handling overhead, and backend load distribution. Check whether the bottleneck is truly Web Dispatcher capacity or a symptom of backend saturation (ICM thread exhaustion, ABAP work process starvation). Analyze traffic patterns and consider horizontal scaling (additional Web Dispatcher instances behind a load balancer).", level: "senior", tags: ["Web Dispatcher", "Fiori", "performance", "ICM"] },
      { id: "sc31", q: "A finance director asks why month-end performance degraded after archiving was paused for six months. How do you explain it?", a: "Unmanaged data growth affects processing volume, index efficiency (bloated tables), backup duration, housekeeping job runtime, and database memory pressure. Archiving is not only a storage activity — it is part of performance governance. Propose a controlled recovery plan: define business-approved retention policies, archive in batches with business sign-off, and restore normal monthly archiving cycles with measurable performance targets.", level: "senior", tags: ["archiving", "SARA", "month-end", "performance"] },
      { id: "sc32", q: "How do you approach cross-region HA design for SAP on AWS?", a: "Separate HA (protects against local/instance failure) from DR (protects against regional failure) — they solve different problems with different cost profiles. Within region: multi-AZ HANA HSR + EC2 Auto Recovery + Pacemaker cluster for ASCS. Cross-region DR: HANA HSR async replication, Route 53 DNS failover, full infrastructure-as-code for fast rebuild. Justify cross-region cost/complexity with business RTO/RPO requirements.", level: "senior", tags: ["AWS", "HA", "DR", "cross-region"] },
      { id: "sc33", q: "A customer wants all Basis alerts forwarded to Teams, email, SMS, and ServiceNow. What would you recommend?", a: "Recommend alert rationalization first. Sending all alerts to all channels creates noise and weakens response quality (alert fatigue). Classify alerts by severity, audience, automation potential, and escalation path. P1/P2 → all channels. P3/P4 → ticket only. Integrate CCMS auto-reaction methods (RZ21) or Cloud ALM alerts selectively. Quality of alert response matters more than quantity of alert channels.", level: "senior", tags: ["alerting", "CCMS", "ServiceNow", "operations"] },
      { id: "sc34", q: "How would you investigate repeated SAP start service failures after OS patching?", a: "Compare service behavior before and after patching. Validate permissions (sidadm ownership of SAP files), shared library versions (ldd disp+work), host agent dependencies, startup scripts, hostname/DNS resolution changes, and security policy changes (SELinux, AppArmor). Check whether the issue is on one host or systemic. If systemic: OS patch rollback on one node first to isolate. Coordinate with OS/security team for library compatibility.", level: "senior", tags: ["OS", "kernel", "startup", "patching"] },
      { id: "sc35", q: "A business unit wants a separate SAP tenant for speed, but IT wants shared landscape efficiency. How do you answer?", a: "Evaluate the request through: business isolation requirements, compliance needs, release autonomy, cost, operations overhead, and integration complexity. Shared landscapes improve standardization and cost efficiency but can reduce agility. Propose a middle path: dedicated client in shared system with independent transport lane, or assess BTP sub-account for cloud-native extensions. The right answer is an operating model decision, not purely technical.", level: "senior", tags: ["landscape", "tenant", "governance", "BTP"] },
      { id: "sc36", q: "The customer wants to use Joule and AI features, but security is concerned. What do you discuss?", a: "Discuss data boundaries (what data Joule can access and process), model governance, prompt handling and data residency, role-based access controls, approval flows for AI-driven actions, tenant configuration (IAS, BTP AI Core setup), and auditability. AI enablement in SAP should be treated like any enterprise capability: valuable, but governed. Show excitement with control — not blind adoption.", level: "senior", tags: ["Joule", "AI", "security", "BTP"] },
      { id: "sc37", q: "A HANA system shows frequent delta merge pressure. What would you do?", a: "Examine table design (oversized main memory delta), write-heavy workload patterns (INSERT-heavy applications), partitioning strategy, merge scheduling (automatic vs. forced), and memory pressure on the HANA host. Identify whether application behavior or data model choices are causing avoidable delta churn. Delta merge pressure often reveals workload-pattern problems — not just database settings. Address at application and schema design levels.", level: "senior", tags: ["HANA", "delta merge", "performance", "memory"] },
      { id: "sc38", q: "How do you defend an investment in automation when the client says the team can just do the tasks manually?", a: "Quantify risk reduction (zero manual errors), consistency (identical execution every time), speed (minutes vs hours), auditability (full log trail), and human dependency reduction (resilience when key staff are absent). Manual work looks cheaper until you calculate outages caused by human error, missed controls, inconsistent execution, and senior resource time consumed by routine operations. Tie automation to business resilience — not cost avoidance alone.", level: "senior", tags: ["automation", "DevOps", "business case", "governance"] },
      { id: "sc39", q: "A hybrid SAP landscape has multiple identity stores and duplicate users. What is your cleanup strategy?", a: "Establish identity source of truth (corporate AD or IDP), define provisioning flow (IPS for SAP), deprovisioning rules (JML — Joiner/Mover/Leaver process), privileged access model, and reconciliation logic. Align IAS, IPS, on-prem LDAP, and SAP application user models. The goal is not just cleanup — it is a sustainable identity operating model that prevents future drift. Reconcile via SUIM/IPS audit reports.", level: "senior", tags: ["IAS", "IPS", "identity", "governance"] },
      { id: "sc40", q: "You are asked to explain the role of Basis in a clean core S/4HANA strategy. How would you answer?", a: "Basis helps operationalize clean core through platform standards, integration governance, transport control, extension decisions, security architecture, and lifecycle management. Clean core is not only a development concept — it requires technical governance and operating discipline. Basis defines the extension boundaries (S_DEVELOP, transport routing), validates ATC compliance, and enforces ABAP Cloud readiness. Where Basis leads, clean core succeeds.", level: "senior", tags: ["clean core", "Basis", "S/4HANA", "governance"] },
      { id: "sc41", q: "SAP is available internally but unreachable externally through reverse proxy. What is your troubleshooting sequence?", a: "Start at the edge: DNS resolution, TLS certificate validity on the proxy, proxy health (access logs, error logs), route rules (URL path mapping), and public endpoint reachability (curl from external). Then validate SAP Web Dispatcher routing, ICM service activation (SICF), backend service health, and authentication behavior (SAML redirect, certificate). Move layer by layer rather than jumping directly into SAP transactions.", level: "senior", tags: ["Web Dispatcher", "reverse proxy", "SICF", "TLS"] },
      { id: "sc42", q: "The ops team wants to clone production to refresh QA, but compliance raises concerns. How do you proceed?", a: "Define masking requirements (PII, financial data — use TDMS or custom scripts), user access controls (lock production users in QA, disable email interfaces), interface isolation (disable/redirect outbound IDocs, RFC connections), legal constraints, and obtain data handling approvals before any refresh. Technical refresh without compliance control is a data breach risk. Document the approval chain and masking evidence.", level: "senior", tags: ["QA refresh", "compliance", "GDPR", "data masking"] },
      { id: "sc43", q: "How do you handle stakeholder pressure during a Sev1 incident when the root cause is not yet known?", a: "Separate incident command from technical troubleshooting — one person leads communications, another leads technical investigation. Give clear, time-bound status updates based only on facts (every 20-30 minutes). State what is known versus what is still under investigation. Avoid speculation. Assign clear owners for each investigation thread. Strong incident leadership is about clarity, rhythm, and containment under uncertainty — not bravado.", level: "senior", tags: ["incident", "P1", "stakeholder", "communication"] },
      { id: "sc44", q: "How has the focus of Basis interviews changed compared with five years ago?", a: "The focus has shifted from transaction-code recall and administration procedures to architecture decisions, cloud operating models, identity governance, resilience design, automation, and business communication. Deep technical troubleshooting is still important, but modern interviewers expect platform thinking, hybrid cloud literacy, security awareness, and the ability to explain trade-offs to business stakeholders — not just to run SM50.", level: "senior", tags: ["career", "skills", "2026", "architecture"] },
      { id: "sc45", q: "A HANA certificate expiry causes SSL failures for integrated services. What is your remediation approach?", a: "Identify all impacted connections (STRUST, SM59 Type H connections, ICM HTTPS). Renew or replace certificates through the approved trust process (STRUST → System PSE or SSL Client PSE). Validate the full certificate chain (root CA, intermediate, leaf) end to end. Coordinate a controlled deployment window. Update certificate inventory with new expiry dates and configure proactive expiry monitoring (certificate expiry alert in CCMS or Cloud ALM). Certificate management is an operational capability, not an ad hoc fix.", level: "senior", tags: ["TLS", "STRUST", "certificate", "HANA"] },
      { id: "sc46", q: "Your SAP support model spans an outsourced Basis team and an internal architecture team. How do you maintain quality?", a: "Define clear service boundaries (what is outsourced vs. retained), runbooks with quality gates, escalation paths with SLA ownership, change approval processes, observability standards, and architecture review checkpoints for significant changes. Outsourcing can support operations, but architectural accountability and service governance must remain with the internal team. Quality is measured — not assumed. Use regular audits and KPIs.", level: "senior", tags: ["governance", "outsourcing", "operations", "SLA"] },
      { id: "sc47", q: "A client asks whether SAP workloads should move to containers and Kubernetes. How do you respond?", a: "Not every SAP workload is a container candidate. Core ERP (ABAP) is not supported in Docker/Kubernetes by SAP. Container relevance for SAP: BTP-adjacent workloads (CAP apps, microservices), Integration Suite adapters, and custom Node.js/Python services. Kubernetes is valid for cloud-native extensions. For core SAP: supportability, vendor guidance, and lifecycle clarity must drive the decision — not technology trend.", level: "senior", tags: ["Kubernetes", "containers", "BTP", "architecture"] },
      { id: "sc48", q: "During cutover weekend, a non-SAP dependency fails and blocks SAP go-live. What do you do?", a: "Assess whether the dependency is on the critical path, whether there is a business workaround, and whether go-live criteria are still met without it. Escalate through the cutover command structure with clear options: go, no-go, or limited-go (with defined workaround). Document the risk accepted. The answer shows governance discipline under pressure — not panic or improvised decisions.", level: "senior", tags: ["cutover", "go-live", "governance", "dependency"] },
      { id: "sc49", q: "A customer wants to reduce Basis headcount after moving to private cloud. What is your response?", a: "Some operational tasks may reduce, but skill demand shifts toward: architecture decisions, vendor governance, integration control, performance oversight, security, and automation. Private cloud reduces certain infrastructure burdens but does not eliminate the need for technical ownership and informed decision-making. Teams that downsize Basis too aggressively in cloud often discover the hidden cost when integrations fail or compliance gaps appear.", level: "senior", tags: ["private cloud", "headcount", "career", "governance"] },
      { id: "sc50", q: "How do you evaluate readiness for an SAP technical upgrade?", a: "Assess: custom code compatibility (SCI/ATC readiness check), add-on compatibility (Maintenance Planner), kernel and DB prerequisites (PAM), interface dependency mapping, infrastructure capacity validation, test scope coverage, fallback path definition, and business freeze window alignment. Upgrade readiness is a combination of technical fit, operational readiness, and business preparedness — all three must be green before committing to a production window.", level: "senior", tags: ["upgrade", "readiness", "SUM", "S/4HANA"] },
      { id: "sc51", q: "A company wants a single monitoring dashboard for SAP and non-SAP estates. What should the architecture consider?", a: "Consider metric normalization (common schema for SAP CCMS, OS metrics, cloud metrics), event correlation, dependency mapping (service catalog), log aggregation (Splunk/ELK with SAP adapters), alert ownership, and access control (who sees production data). A unified dashboard must represent operational truth — not just one screen. Without ownership and context, it becomes cosmetic rather than useful.", level: "senior", tags: ["monitoring", "observability", "Cloud ALM", "architecture"] },
      { id: "sc52", q: "What is the biggest operational risk in modern SAP Basis, in your view?", a: "The biggest risk is assuming managed platforms remove the need for deep technical governance. In reality, complexity has moved into integration, security, shared responsibility, automation, and cross-platform dependency management. Teams that do not evolve from administration to architecture become operationally fragile — especially when incidents cross SAP, cloud, and non-SAP boundaries simultaneously. Governance and technical depth must grow together.", level: "senior", tags: ["risk", "governance", "2026", "architecture"] },
    ],
  },
  {
    id: "killer2026",
    title: "Killer Interview Q&A",
    icon: React.createElement(Zap, { className: "w-5 h-5" }),
    color: "text-rose-600",
    bg: "bg-rose-50",
    questions: [
      { id: "kq01", q: "Why is Basis still critical in 2026 if SAP is moving everything to cloud?", a: "Because business continuity, architecture control, resilience, integration, security, and lifecycle governance still need ownership even when infrastructure is partially managed. Cloud shifts who runs servers — it does not eliminate the need for design quality and operational accountability.", level: "senior", tags: ["career", "cloud", "2026", "strategy"] },
      { id: "kq02", q: "What is the first mistake weak candidates make in outage questions?", a: "They jump into transaction codes before defining the failure scope and affected layer. Strong candidates always classify the problem first: network, OS, database, SAP instance, or front-end — before opening any transaction.", level: "senior", tags: ["incident", "troubleshooting", "methodology"] },
      { id: "kq03", q: "What is the difference between high availability and disaster recovery?", a: "High availability minimizes local service interruption using redundancy at the same site (HANA HSR synchronous, Pacemaker cluster). Disaster recovery restores service after a larger-scale failure — typically at another site or region — and is governed by business-defined RTO and RPO targets.", level: "mid", tags: ["HA", "DR", "RTO", "RPO"] },
      { id: "kq04", q: "Why does a production restart not count as root cause analysis?", a: "Because it restores service without explaining or preventing the underlying failure mechanism. The next incident is virtually guaranteed to be identical. RCA means finding the why, not just the how-to-restart.", level: "senior", tags: ["RCA", "incident", "operations"] },
      { id: "kq05", q: "What is the most important architectural question before choosing RISE with SAP?", a: "Who owns which responsibilities after go-live: SAP, hyperscaler, partner, and customer. The shared responsibility model must be explicit — gaps in ownership become outages.", level: "senior", tags: ["RISE", "architecture", "responsibility"] },
      { id: "kq06", q: "Why do many S/4HANA performance issues remain after migration?", a: "Because legacy custom code and inefficient processing patterns are often moved unchanged into the new platform. HANA's in-memory advantage is only realized when code uses set-based processing, push-down, and CDS views — not when old ABAP patterns are migrated as-is.", level: "senior", tags: ["S/4HANA", "performance", "HANA", "clean code"] },
      { id: "kq07", q: "What does Clean Core mean in practical terms?", a: "Keep the ERP core as standard as possible by using only SAP-released extension patterns: BAdIs, CDS Views, BAPIs, and BTP side-by-side extensions. No direct modifications to SAP standard objects. Governance enforces this through ATC checks, transport controls, and architecture review.", level: "senior", tags: ["clean core", "extensibility", "S/4HANA"] },
      { id: "kq08", q: "What is the biggest mistake in SAP automation?", a: "Automating unstable or badly governed processes without control, monitoring, and rollback. Automation amplifies both good and bad processes. Automate governance first, then volume.", level: "senior", tags: ["automation", "governance", "DevOps"] },
      { id: "kq09", q: "What is one sign a candidate does not understand HANA deeply?", a: "They recommend routine restarts instead of analyzing workload, memory behavior, delta merge pressure, and data-growth patterns. Restarting HANA weekly is a symptom of governance failure, not a management technique.", level: "senior", tags: ["HANA", "memory", "operations"] },
      { id: "kq10", q: "Why do transport issues continue in mature SAP landscapes?", a: "Because governance, sequencing, dependency visibility, and release discipline are often weaker than expected. The transport tooling is mature — the process around it rarely is. Most RC8 failures are preventable with proper approvals and pre-import checks.", level: "senior", tags: ["transport", "governance", "STMS", "RC8"] },
      { id: "kq11", q: "What is the real value of SAP Cloud ALM?", a: "It supports lifecycle and operations visibility for modern hybrid and cloud-centric SAP landscapes — implementation monitoring, operations dashboards, alert management, and health checks across systems that Solution Manager was not designed to cover natively.", level: "senior", tags: ["Cloud ALM", "SolMan", "hybrid"] },
      { id: "kq12", q: "What makes identity design a Basis topic now?", a: "Because SAP operations increasingly depend on federated authentication, automated provisioning, trust configuration, MFA, and cross-platform access governance (IAS, IPS, SNC, SAML). Identity failures cause outages — not just security incidents.", level: "senior", tags: ["IAS", "IPS", "SSO", "identity"] },
      { id: "kq13", q: "Why do interviewers ask about observability instead of only monitoring?", a: "Because hybrid architectures need correlation across logs, metrics, events, and dependencies — not just threshold alerts. Monitoring tells you a metric exceeded a threshold; observability helps you understand why, across which components, and at what dependency layer.", level: "senior", tags: ["observability", "monitoring", "hybrid"] },
      { id: "kq14", q: "What is the biggest risk in a system refresh from production to QA?", a: "Sensitive data exposure and uncontrolled downstream connectivity. If masking and interface isolation are not enforced, PII reaches QA users and outbound IDocs/emails go to production partners from a test system.", level: "senior", tags: ["QA refresh", "GDPR", "data masking", "interfaces"] },
      { id: "kq15", q: "Why is month-end performance often a governance issue, not only a hardware issue?", a: "Because scheduling conflicts, unarchived data growth, custom code inefficiency, and missing index maintenance are the real drivers in most landscapes. Hardware is rarely the bottleneck — process design and data governance usually are.", level: "senior", tags: ["month-end", "performance", "archiving", "governance"] },
      { id: "kq16", q: "What separates a senior Basis architect from an administrator in interviews?", a: "The architect explains trade-offs, ownership models, risk quantification, and business impact — not only the technical steps. Administrators describe what they do; architects explain why they made a specific design decision and what they gave up.", level: "senior", tags: ["career", "architect", "skills"] },
      { id: "kq17", q: "Why is shared responsibility important in SAP cloud operations?", a: "Because managed service does not mean fully outsourced accountability. In IaaS, customers own OS and above. In RISE, SAP manages the platform but the customer still owns integration design, security configuration, user governance, and business continuity decisions.", level: "senior", tags: ["RISE", "cloud", "responsibility", "governance"] },
      { id: "kq18", q: "What makes BTP relevant to Basis interviews?", a: "Extensions, integration (Integration Suite), identity (IAS/IPS), Cloud Connector, destinations, and hybrid connectivity now influence core SAP architecture decisions. A Basis consultant who cannot discuss BTP is missing half the modern SAP landscape.", level: "senior", tags: ["BTP", "Basis", "architecture", "2026"] },
      { id: "kq19", q: "What is a common trap in security interview questions?", a: "Answering only with password policies and role administration while missing IAM architecture, trusted RFC risks, certificate governance, SNC configuration, privileged access management, and auditability. Security in SAP is a system-level discipline, not a user administration task.", level: "senior", tags: ["security", "IAM", "SNC", "certificates"] },
      { id: "kq20", q: "Why is certificate management now a high-value Basis topic?", a: "Because expired or mismanaged certificates break APIs, Fiori SSO, BTP integrations, IDoc HTTPS interfaces, and hybrid trust chains simultaneously. Certificate expiry is now one of the most common preventable outage causes in modern SAP landscapes.", level: "senior", tags: ["certificates", "TLS", "STRUST", "operations"] },
      { id: "kq21", q: "What do weak candidates miss when asked about DR?", a: "They describe backup procedures and ignore recovery orchestration, documented recovery steps, actual restore testing, DNS failover, application layer restart sequence, and invocation criteria. A backup that has never been restored is not a DR capability.", level: "senior", tags: ["DR", "backup", "recovery", "testing"] },
      { id: "kq22", q: "Why are cloud migration interviews more difficult than classic Basis interviews?", a: "Because they test business alignment, architecture design, dependency mapping, security governance, and operating model maturity simultaneously — in addition to deep technical knowledge of SAP itself.", level: "senior", tags: ["cloud migration", "architecture", "interview", "2026"] },
      { id: "kq23", q: "What is the biggest misconception about private cloud for SAP?", a: "That it removes the need for deep internal technical capability. Private cloud shifts operational burden but not technical accountability. Integration, security, and performance still require skilled SAP technical architects and administrators.", level: "senior", tags: ["private cloud", "governance", "skills"] },
      { id: "kq24", q: "Why is user provisioning not just a security team topic?", a: "Because provisioning, deprovisioning, and trust configuration directly impact operational continuity. Broken provisioning means users cannot access systems after a role change. Delayed deprovisioning creates security exposure. Both are operational failures as much as security ones.", level: "mid", tags: ["IPS", "provisioning", "IAM", "operations"] },
      { id: "kq25", q: "What does a good answer to 'the system is slow' start with?", a: "A scope question: who is affected, what specific action is slow, since when did it start, and at which layer does it occur? Scope first, then measurement, then analysis. Jumping to transactions without scope definition wastes time and looks junior.", level: "mid", tags: ["performance", "methodology", "troubleshooting"] },
      { id: "kq26", q: "Why do interviewers ask about Clean Core and ABAP Cloud now?", a: "Because SAP's strategy is pushing extensibility discipline and modernization. Candidates who cannot explain the difference between modifications, BAdIs, and ABAP Cloud development extensions are not ready for modern S/4HANA governance roles.", level: "senior", tags: ["clean core", "ABAP Cloud", "BTP", "S/4HANA"] },
      { id: "kq27", q: "What is the biggest hidden cost in SAP landscapes?", a: "Operational complexity caused by unmanaged integrations, undocumented exceptions, manual workarounds, and weak governance. This hidden technical debt manifests as slower change cycles, longer incident resolution times, and higher risk in every upgrade.", level: "senior", tags: ["technical debt", "governance", "cost"] },
      { id: "kq28", q: "What does 'business continuity' mean in a Basis interview answer?", a: "Keeping the business service running or restorable within agreed tolerance — not just keeping a server alive. Business continuity is measured in user impact, financial exposure, and recovery time — not in server uptime percentages.", level: "senior", tags: ["business continuity", "HA", "RTO"] },
      { id: "kq29", q: "Why is cloud sizing not a one-time task?", a: "Because workload patterns, user base, integrations, and data volumes change significantly after migration. Initial sizing is a starting point. Ongoing right-sizing using cloud cost tools (AWS Cost Explorer, Azure Advisor) is required every 6-12 months.", level: "mid", tags: ["sizing", "cloud", "AWS", "Azure"] },
      { id: "kq30", q: "What is a weak answer to a transport governance question?", a: "'We move DEV to QAS to PRD.' A strong answer covers: approval process, emergency transport lane, dependency sequencing, pre-import checks, rollback procedures, post-import validation, and audit trail requirements.", level: "senior", tags: ["transport", "governance", "STMS"] },
      { id: "kq31", q: "What is the biggest danger in over-monitoring?", a: "Alert fatigue — the team becomes desensitized to alerts and starts ignoring or auto-resolving them, which means real incidents are missed. Quality of alert response matters far more than quantity of alerts generated.", level: "mid", tags: ["monitoring", "alerting", "operations"] },
      { id: "kq32", q: "Why is hybrid SAP support harder than on-premise only?", a: "Because responsibility, tooling, identity, connectivity, and troubleshooting span multiple providers and layers — SAP infrastructure, cloud hyperscaler, network teams, BTP platform, and on-premise legacy systems. Each boundary is a potential gap.", level: "senior", tags: ["hybrid", "support", "operations"] },
      { id: "kq33", q: "What is the real meaning of resiliency in SAP architecture?", a: "The ability to absorb failure, recover predictably, and continue business service within acceptable limits — regardless of whether the failure is a server crash, a network partition, a bad transport, or a certificate expiry.", level: "senior", tags: ["resilience", "architecture", "HA", "DR"] },
      { id: "kq34", q: "Why do many candidates fail cloud questions after certification?", a: "Because they know service names but cannot connect them to SAP operating realities. They know what S3 or Blob Storage is, but cannot explain how backup-to-object storage integrates with HANA backint, or how VNet peering affects DIAG protocol latency.", level: "senior", tags: ["cloud", "certification", "AWS", "Azure"] },
      { id: "kq35", q: "What is the best response when root cause is still unknown during a Sev1 incident?", a: "Communicate clearly what is known, what is still under investigation, what the next update time is, and who is leading which investigation thread. Repeat this cadence every 15-30 minutes. Do not speculate about root cause under stakeholder pressure.", level: "senior", tags: ["incident", "P1", "communication"] },
      { id: "kq36", q: "Why is data growth a Basis issue and not only a functional issue?", a: "Because it directly affects database performance, backup window duration, maintenance job runtime, recovery time, HANA memory pressure, and infrastructure cost. Data governance is a joint accountability — functional teams decide retention, Basis implements and monitors the technical impact.", level: "senior", tags: ["data growth", "archiving", "HANA", "performance"] },
      { id: "kq37", q: "What is the wrong way to discuss AI in SAP interviews?", a: "Treating AI as a buzzword and listing use cases without discussing governance, data privacy, security boundaries, operational controls, and measurable value. Interviewers reward candidates who can explain how Joule or AI Core are governed, not just that they exist.", level: "senior", tags: ["AI", "Joule", "governance", "2026"] },
      { id: "kq38", q: "Why do interviewers care about stakeholder communication in technical roles?", a: "Because major SAP incidents are business events. A technically brilliant responder who cannot communicate status clearly to business stakeholders creates secondary damage — loss of confidence, poor decisions, and escalation chaos on top of the actual outage.", level: "senior", tags: ["communication", "incident", "stakeholder"] },
      { id: "kq39", q: "What is the most dangerous phrase in SAP operations?", a: "'It worked after restart, so it is fixed.' This phrase signals that root cause analysis was abandoned, recurrence is probable, and no preventive action was taken. It is the hallmark of reactive rather than proactive operations.", level: "senior", tags: ["RCA", "operations", "culture"] },
      { id: "kq40", q: "Why is failover testing more important than DR documentation?", a: "Because untested DR plans almost always fail in real emergencies. Documentation describes the intended process; testing reveals actual gaps — missing runbook steps, changed IP addresses, expired credentials, DNS TTL issues, and timing surprises.", level: "senior", tags: ["DR", "failover", "testing", "HA"] },
      { id: "kq41", q: "What shows maturity in a transport failure answer?", a: "Containing business risk first (assess what is broken, consider rollback), then identifying root cause (log analysis, dependency mapping), defining the correction path (correction transport or rollback), and proposing governance improvement (what process failed?). Mature responders separate urgency from analysis.", level: "senior", tags: ["transport", "RC8", "maturity", "governance"] },
      { id: "kq42", q: "What is one practical reason Basis must understand BTP?", a: "Because side-by-side extensions, Fiori apps, identity flows, Integration Suite iFlows, and Cloud Connector configurations directly affect end-to-end service operation. When a BTP-based Fiori app fails, Basis is the first responder — not the BTP development team.", level: "senior", tags: ["BTP", "Basis", "Fiori", "integration"] },
      { id: "kq43", q: "Why is latency analysis essential in SAP cloud design?", a: "Because even well-sized systems perform badly when dependent systems are too far apart or poorly connected. RFC, IDOC, and API latency accumulate across integration hops. Co-location strategy (same region, same AZ, dedicated Express Route or Direct Connect) is a critical architecture decision.", level: "senior", tags: ["latency", "cloud", "RFC", "architecture"] },
      { id: "kq44", q: "What is the biggest mistake in role design remediation?", a: "Removing access without understanding business process dependency and technical-user requirements. Aggressive role remediation that locks critical RFC users or removes authorizations from automated processes creates operational outages. Remediate with impact analysis first.", level: "senior", tags: ["security", "SU01", "authorization", "roles"] },
      { id: "kq45", q: "Why is observability valuable during hybrid outages?", a: "It connects symptoms across SAP ABAP, middleware (Integration Suite), networks, APIs, BTP services, and cloud infrastructure into one failure story. Without cross-layer correlation, each team sees only their piece and the resolution takes hours longer.", level: "senior", tags: ["observability", "hybrid", "outage", "monitoring"] },
      { id: "kq46", q: "What does 'operating model' mean in SAP interviews?", a: "Who does what, with which tools, under which controls, with what escalation path, and with what service level commitment. An operating model defines people, process, and technology together — not just the technology layer.", level: "senior", tags: ["operating model", "governance", "RACI"] },
      { id: "kq47", q: "Why is Basis not only a technical function anymore?", a: "Because it now sits at the intersection of architecture design, cloud governance, integration security, business continuity, automation, and vendor management. The value of a modern Basis architect is as much in governance decisions and communication as in transaction-level technical execution.", level: "senior", tags: ["career", "Basis", "architect", "2026"] },
      { id: "kq48", q: "What is the difference between patching and lifecycle management?", a: "Patching is one activity: applying a specific OS, kernel, or HANA patch. Lifecycle management is the governed end-to-end process of keeping the entire platform healthy, secure, supportable, and aligned to the vendor roadmap — covering versions, patches, upgrades, add-ons, and dependencies.", level: "mid", tags: ["patching", "lifecycle", "governance"] },
      { id: "kq49", q: "Why is an SAP system copy project risky even when technically routine?", a: "Because data exposure (PII in non-production), interface bleed-through (outbound IDocs, email), inconsistent masking, user access confusion, and downstream connectivity risks can create real business and compliance incidents — even when the technical copy itself succeeds.", level: "senior", tags: ["system copy", "GDPR", "compliance", "risk"] },
      { id: "kq50", q: "What is the best way to answer a trap question you are unsure about?", a: "State your assumptions explicitly, define the relevant decision factors, and answer structurally rather than guessing specifics. Interviewers reward analytical thinking and intellectual honesty far more than confident wrong answers. 'I would approach this by considering...' is always valid.", level: "senior", tags: ["interview", "methodology", "career"] },
      { id: "kq51", q: "What is the current direction of high-value SAP Basis careers?", a: "Toward cloud architecture, platform governance, security design, automation engineering, observability, and transformation leadership. The highest-value Basis professionals combine deep SAP technical knowledge with cloud platform literacy, business communication, and the ability to design governed operating models for complex hybrid landscapes.", level: "senior", tags: ["career", "skills", "architecture", "2026"] },
    ],
  },
];
